	$("#tabs").tabs({
	    activate: function (event, ui) {
	        var $t = ui.newPanel.find('table');
	        if ($t.length) {
	            if ($t[0].config) {
	                $t.trigger('applyWidgets');
	            } else {
	                $t.tablesorter({
	                    theme: 'bootstrap',
	                    widgets: ["zebra"]
