                // info file arrangement is as follows:
                //AgentId
                //CampaignName
                //ProjectId
                //LeadName
                //PhoneNumber
                //ResultCode
                //TimeStamp (yyyyMMdd)
                //CallCenterId
                //UploadUrl
                //FileName
                //Upload retries
                for (int idx = 0; idx < info.Length; idx++)
                {
